require"UI.UIBase"require"UI.UIBlock"require"UI.MomentTree"require"UI.UI_Activity_Moments_Cell"UI_Activity_Moments=UIBase:Inherit()function UI_Activity_Moments:OnCreate(a)self.activity_id=a;self.cells={}self.template=self.transform:Find('page_moments'):Find('Viewport'):Find('Content'):Find('template')self.template.transform.gameObject:SetActive(false)self.sep_template=self.transform:Find('page_moments'):Find('Viewport'):Find('Content'):Find('sep_template')self.sep_template.transform.gameObject:SetActive(false)self.tail=self.transform:Find('page_moments'):Find('Viewport'):Find('Content'):Find('tail')self.tail:Find('tail'):GetComponent(typeof(UnityEngine.UI.Text)).text=Tools.StrOfLocalization(3445)self.loupe=self.transform:Find('page_loupe')self.loupe_content=self.loupe:Find('content'):GetComponent(typeof(UnityEngine.UI.Image))self.loupe:Find('btn_close'):GetComponent(typeof(UnityEngine.UI.Button)).onClick:AddListener(function()self:Close_Loupe()end)end;function UI_Activity_Moments:OnEnable()self.loupe.gameObject:SetActive(false)local b=self:get_unread()for c=1,#b do local d=ProtoMgr.CreateRequest('Lobby','readSNS')d.id=b[c]LogTool.Info('Activity_Moments','readSNS:'..d.id)LobbyNetMgr.SendRequest('Lobby','readSNS',d,function(e,f)if e or f.error and f.error.code~=0 then LogTool.Error('ActivityMoments','readSNS error: '..pt.block(e)..pt.block(f))end end)local g=UI_Activity.Inst.sns_data.blog;local h=require("Protol.cli_lobby_pb")local i=h.SNSBlog()i.id=b[c]i.read_time=Tools.GetRealTime()table.insert(g,i)end end;function UI_Activity_Moments:get_unread()local b={}self:Init_Moment_Tree()local j=function(k)if UI_Activity.Inst.sns_data then for c=1,#UI_Activity.Inst.sns_data.blog do if UI_Activity.Inst.sns_data.blog[c].id==k then return true end end end;return false end;for c=1,#self.moment_tree.tree.childs do if not j(self.moment_tree.tree.childs[c].id)then table.insert(b,self.moment_tree.tree.childs[c].id)end end;if UI_Activity.Inst.sns_data then for c=1,#UI_Activity.Inst.sns_data.reply do local l=UI_Activity.Inst.sns_data.reply[c].id;local m=MomentTree.GetNode(self.moment_tree.tree,l,0)if m then for n=1,#m.childs do if not j(m.childs[n].id)and Tools.GetRealTime()>UI_Activity.Inst.sns_data.reply[c].reply_time then table.insert(b,m.childs[n].id)end end end end end;return b end;function UI_Activity_Moments:RefreshView()self:Init_Moment_Tree()for c=1,#self.moment_tree.tree.childs do local o=self.cells[c]if not o then local p;if#self.cells<#self.moment_tree.tree.childs and#self.cells>0 then p=UnityEngine.GameObject.Instantiate(self.sep_template,self.transform:Find('page_moments'):Find('Viewport'):Find('Content')).transform;p.transform.gameObject:SetActive(true)end;local q=UnityEngine.GameObject.Instantiate(self.template,self.transform:Find('page_moments'):Find('Viewport'):Find('Content')).transform;q.transform.gameObject:SetActive(true)o=UI_Activity_Moments_Cell:Init(q,self,self.activity_id)o.sep_instance=p;table.insert(self.cells,o)end;o:RefreshData(self.moment_tree.tree.childs[c])o:OnEnable()if o.sep_instance then o.sep_instance:SetAsFirstSibling()end;o.transform:SetAsFirstSibling()end;self.tail:SetAsLastSibling()end;function UI_Activity_Moments:can_reply(k)local r=MomentTree.GetNode(self.moment_tree.tree,k,0)local s=false;for c=1,#r.childs do if r.childs[c].content.choice_id==1 then s=true;if self:get_reply(r.childs[c].id)then return false end end end;return true and s end;function UI_Activity_Moments:has_choice(k)local r=MomentTree.GetNode(self.moment_tree.tree,k,0)local s=false;for c=1,#r.childs do if r.childs[c].content.choice_id==1 then s=true end end;return s end;function UI_Activity_Moments:get_reply(k)if not UI_Activity.Inst.sns_data then return end;for c=1,#UI_Activity.Inst.sns_data.reply do if UI_Activity.Inst.sns_data.reply[c].id==k then return UI_Activity.Inst.sns_data.reply[c]end end end;function UI_Activity_Moments:get_read(k)if not UI_Activity.Inst.sns_data then return end;for c=1,#UI_Activity.Inst.sns_data.blog do if UI_Activity.Inst.sns_data.blog[c].id==k then return UI_Activity.Inst.sns_data.blog[c]end end end;function UI_Activity_Moments:can_show_reply(k)local r=MomentTree.GetNode(self.moment_tree.tree,k,0)if not r then return false end;if r.content.choice_id==0 and r.depth<2 then return true else if r.content.choice_id==1 then return self:get_reply(k)else if r.content.parent_id and r.content.parent_id~=0 and MomentTree.GetNode(self.moment_tree.tree,r.content.parent_id,0).content.choice_id==1 then local t=self:get_reply(r.content.parent_id)if t then return Tools.GetRealTime()>t.reply_time else return false end else return true end end end;LogTool.Error('ActivityMoments','no fallback id: '..k)return true end;function UI_Activity_Moments:contains_like(k)if not UI_Activity.Inst.sns_data then return end;for c=1,#UI_Activity.Inst.sns_data.liked_id do if UI_Activity.Inst.sns_data.liked_id[c]==k then return true end end;return false end;function UI_Activity_Moments:Init_Moment_Tree()local u=ExcelMgr.GetTable('activity','sns_activity')local v={}for w,x in pairs(u)do if x and x.activity_id==self.activity_id and UI_Bag.GetCount(309036)>=x.unlock_item_count and x.pm~=1 and x.disable~=1 then table.insert(v,x)end end;table.sort(v,function(y,z)return y.id<z.id end)self.moment_tree=MomentTree:Init(v)end;function UI_Activity_Moments:Open_Loupe(A)if self.loupe_locking then return end;self.loupe_locking=true;self.loupe.gameObject:SetActive(true)if A=='myres/sns/210703.jpg'and GameMgr.Inst.client_language=='en'then self.loupe_content:SetTexture('pic/myres/sns/210703')else Tools.ImgOfLocalization(A,self.loupe_content,true)end;self.loupe_content:SetNativeSize()self:AnimAlphaIn(self.loupe,{x=0,y=0},0.2,0,function()self.loupe_locking=false end)end;function UI_Activity_Moments:Close_Loupe()if self.loupe_locking then return end;self.loupe_locking=true;self:AnimAlphaOut(self.loupe,{x=0,y=0},0.2,0,function()self.loupe_locking=false;self.loupe.gameObject:SetActive(false)end)end;return UI_Activity_Moments